const months = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
const d = new Date();
d.setDate(d.getDate() - 1);
const imapDate = `${String(d.getDate()).padStart(2,'0')}-${months[d.getMonth()]}-${d.getFullYear()}`;
const isoDate = d.toISOString().split('T')[0];
return [{ json: { imapDate, isoDate } }];

const items = [];
for (const item of $input.all()) {
  const email = item.json;
  const attachmentTexts = [];
  const binaryKeys = Object.keys(item.binary || {});
  for (const key of binaryKeys) {
    const bin = item.binary[key];
    if (bin && bin.mimeType === 'application/pdf') {
      attachmentTexts.push({ name: bin.fileName || key, type: 'pdf_attachment' });
    }
  }
  items.push({
    json: {
      source: 'email',
      subject: email.subject || '(kein Betreff)',
      from: email.from?.value?.[0]?.address || email.from || '',
      date: email.date || new Date().toISOString(),
      body: (email.text || email.textHtml || '').substring(0, 3000),
      attachments: attachmentTexts,
      binary_keys: binaryKeys.filter(k => item.binary?.[k]?.mimeType === 'application/pdf')
    },
    binary: item.binary
  });
}
return items;

const result = $input.first().json;
const docs = result.results || [];
return docs.map(doc => ({
  json: {
    source: 'paperless',
    subject: doc.title || 'Unbekannt',
    from: 'paperless-ngx',
    date: doc.created || doc.modified || new Date().toISOString(),
    body: (doc.content || '').substring(0, 3000),
    attachments: []
  }
}));

const xmlText = $input.first().json.data || $input.first().json.body || '';
const cutoff = new Date(Date.now() - 25 * 60 * 60 * 1000);
const hrefMatches = xmlText.match(/<[^:>]*:href>([^<]+)<\/[^:>]*:href>/g) || [];
const lmMatches = xmlText.match(/<[^:>]*:getlastmodified>([^<]+)<\/[^:>]*:getlastmodified>/g) || [];
const ctMatches = xmlText.match(/<[^:>]*:getcontenttype>([^<]+)<\/[^:>]*:getcontenttype>/g) || [];
const files = [];
for (let i = 0; i < hrefMatches.length; i++) {
  const href = hrefMatches[i].replace(/<[^>]+>/g, '');
  const lm = lmMatches[i] ? new Date(lmMatches[i].replace(/<[^>]+>/g, '')) : null;
  const ct = ctMatches[i] ? ctMatches[i].replace(/<[^>]+>/g, '') : '';
  if (ct.includes('application/pdf') && lm && lm > cutoff) {
    files.push({ href, lastModified: lm.toISOString(), name: href.split('/').pop() });
  }
}
if (files.length === 0) return [{ json: { skip: true } }];
return files.map(f => ({ json: f }));

return $input.all().map(item => ({
  json: {
    source: 'nextcloud',
    subject: item.json.fileName || item.json.name || 'nextcloud-dokument.pdf',
    from: 'Nextcloud',
    date: new Date().toISOString(),
    body: (item.json.text || item.json.content || '').substring(0, 3000),
    attachments: []
  }
}));

const items = $input.all().filter(i => !i.json.skip && (i.json.body || '').trim().length > 10);
if (items.length === 0) {
  return [{ json: { skip: true, reason: 'Keine Inhalte zum Analysieren' } }];
}
const maxItems = 15;
const selected = items.slice(0, maxItems);
const contentParts = [];
for (let idx = 0; idx < selected.length; idx++) {
  const item = selected[idx].json;
  contentParts.push(`=== Dokument ${idx + 1}: ${item.subject} ===`);
  contentParts.push(`Von: ${item.from}`);
  contentParts.push(`Datum: ${item.date}`);
  if (item.body) contentParts.push(`Inhalt:\n${item.body.substring(0, 2000)}`);
  contentParts.push('');
}
return [{ json: {
  userMessage: contentParts.join('\n').substring(0, 14000),
  itemCount: selected.length
}}];

const response = $input.first().json;
const text = response?.content?.[0]?.text || '{"items":[]}';
let parsed;
try {
  parsed = JSON.parse(text);
} catch (e) {
  const match = text.match(/\{[\s\S]*\}/);
  if (match) {
    try { parsed = JSON.parse(match[0]); } catch { parsed = { items: [] }; }
  } else {
    parsed = { items: [] };
  }
}
const items = parsed.items || [];
if (items.length === 0) return [{ json: { skip: true, reason: 'Kein Handlungsbedarf erkannt' } }];
console.log(`Claude hat ${items.length} Handlungseinträge erkannt`);
return items.map(item => ({ json: item }));

const action = $json;
const today = new Date();
const reminderDaysBefore = 3;
let dueDate;
if (action.due_date && action.due_date !== 'null') {
  dueDate = new Date(action.due_date + 'T00:00:00');
  if (isNaN(dueDate.getTime())) dueDate = new Date(today.getTime() + 7 * 86400000);
} else {
  dueDate = new Date(today.getTime() + 7 * 86400000);
}
const reminderDate = new Date(dueDate.getTime() - reminderDaysBefore * 86400000);
const tomorrow = new Date(today.getTime() + 86400000);
if (reminderDate < tomorrow) reminderDate.setTime(tomorrow.getTime());
const pad = n => String(n).padStart(2, '0');
const formatDate = d => `${d.getFullYear()}${pad(d.getMonth()+1)}${pad(d.getDate())}`;
const uid = `email-analyzer-${Date.now()}-${Math.random().toString(36).substr(2,9)}@analyzer`;
const dtstart = formatDate(reminderDate);
const dtend = formatDate(new Date(reminderDate.getTime() + 86400000));
const dtstamp = new Date().toISOString().replace(/[-:]/g,'').replace(/\.\d{3}/,'') + 'Z';
const title = `[Analyzer] ${action.title || 'Aufgabe'}`;
const desc = [
  action.description || '',
  '',
  `Aktion: ${action.action || ''}`,
  action.amount ? `Betrag: ${action.amount}` : '',
  `Priorität: ${action.priority || 'mittel'}`,
  `Fällig: ${action.due_date || 'nicht angegeben'}`,
  `Erstellt: ${today.toLocaleDateString('de-DE')} (Email-Analyzer)`
].filter(Boolean).join('\n').replace(/,/g, '\\,').replace(/\n/g, '\\n');
const ical = [
  'BEGIN:VCALENDAR',
  'VERSION:2.0',
  'PRODID:-//Email Analyzer//DE',
  'BEGIN:VEVENT',
  `UID:${uid}`,
  `DTSTAMP:${dtstamp}`,
  `DTSTART;VALUE=DATE:${dtstart}`,
  `DTEND;VALUE=DATE:${dtend}`,
  `SUMMARY:${title}`,
  `DESCRIPTION:${desc}`,
  'BEGIN:VALARM',
  'ACTION:DISPLAY',
  `DESCRIPTION:Erinnerung: ${action.title || 'Aufgabe'}`,
  'TRIGGER:PT9H',
  'END:VALARM',
  'END:VEVENT',
  'END:VCALENDAR'
].join('\r\n');
return [{ json: { ical, uid, title, reminderDate: reminderDate.toISOString().split('T')[0] } }];

const results = $input.all();
const successful = results.filter(r => !r.json.error).length;
console.log(`Email-Analyzer abgeschlossen: ${successful}/${results.length} Termine erstellt`);
return [{ json: { message: `${successful} Kalendereinträge erstellt`, timestamp: new Date().toISOString() } }];
